solution_code:
#include <iostream>

inline int clampTo100(int v) {
    if (v < 0) return 0;
    if (v > 100) return 100;
    return v;
}

int main() {
    int value;
    std::cin >> value;
    std::cout << clampTo100(value) << "\n";
    return 0;
}

