inline int celsiusToFahrenheit(int c) {
    // Bug: wrong order of operations
    return (c + kOffset) * 9 / 5;
}

int main() {
    int celsius;
    std::cin >> celsius;
    std::cout << celsius << " C = " << celsiusToFahrenheit(celsius) << " F\n";
    return 0;
}

solution_code:
#include <iostream>

inline const int kOffset = 32;

inline int celsiusToFahrenheit(int c) {
    return c * 9 / 5 + kOffset;
}

int main() {
    int celsius;
    std::cin >> celsius;
    std::cout << celsius << " C = " << celsiusToFahrenheit(celsius) << " F\n";
    return 0;
}
